<section class="admin-page-head"><div><p class="eyebrow">FULFILLMENT</p><h1>Centru expediții</h1></div><a class="admin-button secondary" href="<?= e(url('/admin/setari/livrare')) ?>">Configurare curieri</a></section><section class="kpi-grid three"><article><small>AWB total</small><strong><?= count($items) ?></strong></article><article><small>În tranzit</small><strong><?= count(array_filter($items,fn($x)=>$x['status']==='in_transit')) ?></strong></article><article><small>Necesită atenție</small><strong><?= count(array_filter($items,fn($x)=>str_contains($x['status'],'retry'))) ?></strong></article></section><section class="admin-panel"><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Comandă</th><th>Curier</th><th>AWB</th><th>Status</th><th>Actualizat</th></tr></thead><tbody><?php foreach($items as $item): ?><tr><td><a href="<?= e(url('/admin/comenzi/'.$item['order_id'])) ?>"><?= e($item['order_number']) ?></a></td><td><?= e($item['provider_name']??'Manual') ?></td><td><?= e($item['awb']??'—') ?></td><td><?= e($item['status']) ?></td><td><?= date('d.m.Y H:i',strtotime($item['updated_at'])) ?></td></tr><?php endforeach; ?></tbody></table></div></section>

